# Riemann R function via Gram series
def riemann_R(x):
    if x <= 0:
        return 0.0
    lnx = math.log(x)
    total = 1.0
    term = 1.0
    for k in range(1, 200):
        term *= lnx / (k * (k + 1))  # ln(x)^k / (k * k! * zeta(k+1)) approx
        # More precise: use Mobius function
        total += term / _zeta_approx(k + 1)
        if abs(term) < 1e-15:
            break
    return total

def _zeta_approx(s):
    """Approximate zeta(s) for s >= 2."""
    if s == 2:
        return math.pi**2 / 6
    if s == 3:
        return 1.2020569031595942
    if s == 4:
        return math.pi**4 / 90
    # For large s, zeta(s) ~ 1
    total = 0.0
    for k in range(1, 100):
        total += 1.0 / k**s
        if 1.0 / k**s < 1e-15:
            break
    return total

# Inverse Riemann R: given n, find x such that R(x) = n
def riemann_R_inv(n):
    if n <= 1:
        return 2.0
    # Initial guess: n * log(n)
    x = n * math.log(n)
    for _ in range(100):
        rx = riemann_R(x)
        if abs(rx - n) < 0.001:
            break
        # Newton step: R'(x) ~ 1/log(x)
        deriv = 1.0 / math.log(x) if x > 1 else 1.0
        x += (n - rx) / deriv
        x = max(x, 2.0)
    return x

